"use strict";parserFactory.register("shubaowb.com",()=>new ShubaowbParser);class ShubaowbParser extends Parser{constructor(){super()}async getChapterUrls(e,t){let r=this.getUrlsOfTocPages(e);return await this.getChaptersFromAllTocPages([],this.chaptersFromDom,r,t)}chaptersFromDom(e){return[...e.querySelectorAll(".book_last dd a")].map(e=>util.hyperLinkToChapter(e))}getUrlsOfTocPages(e){return[...e.querySelector(".listpage").querySelectorAll("option")].map(e=>{let t=e.value;return t.startsWith("/novel")||(t="/novel"+t),"https://shubaowb.com"+t})}findContent(e){return e.querySelector("#chaptercontent")}extractTitleImpl(e){return e.querySelector("span.title1")}findChapterTitle(e){return e.querySelector("span.title1")}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll(".book_about")]}}